void solve(int CASE)
{
	string s; cin >> s;
	if (s.size() == 1) {
		cout << s << endl;
		return;
	}
	var cnt = vector<ll>(10);
	for (char c : s)cnt[c - '0']++;
	fa(i, 1, 900000) {
		var ncnt = cnt;
		ll now = i;
		while (now > 9) {
			ll x = now, sum = 0;
			while (x) {
				sum += x % 10;
				ncnt[x % 10]--;
				x /= 10;
			}
			now = sum;
		}
		ncnt[now]--;

		ll sum = 0;
		bool ok = 1;
		fa(i, 0, 9)if (ncnt[i] < 0) {
			ok = 0;
			break;
		}
		if (!ok)continue;

		fa(i, 1, 9)sum += ncnt[i] * i;
		if (sum == i) {
			string ans;
			fb(i, 9, 0)while (ncnt[i]--)ans.pb(i + '0');

			ll now = i;
			while (now > 9) {
				ll x = now, sum = 0;
				string tmp;
				while (x) {
					sum += x % 10;
					tmp.pb(x % 10 + '0');
					x /= 10;
				}
				reverse(all(tmp));
				ans.insert(ans.end(), all(tmp));
				now = sum;
			}
			ans.pb(now + '0');

			cout << ans << endl;
			return;
		}
	}
	return;
}
